const jwt = require('jsonwebtoken');

const JWT_SECRET = process.env.JWT_SECRET; // Ensure this is set in your environment
const JWT_ISSUER = process.env.JWT_ISSUER; // Ensure this is set in your environment
const JWT_AUDIENCE = process.env.JWT_AUDIENCE; // Ensure this is set in your environment

const jwtMiddleware = (req, res, next) => {
    const token = req.headers['authorization']?.split(' ')[1];

    if (!token) {
        return res.status(401).json({ message: 'Authorization token is required' });
    }

    jwt.verify(token, JWT_SECRET, { algorithms: ['RS256'], issuer: JWT_ISSUER, audience: JWT_AUDIENCE }, (err, decoded) => {
        if (err) {
            return res.status(401).json({ message: 'Invalid token', error: err.message });
        }

        req.user = decoded; // Attach user info to request
        next();
    });
};

module.exports = jwtMiddleware;